import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/prisma";

export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ scanId: string }> }
) {
  try {
    const { scanId } = await params;

    const scan = await prisma.scan.findUnique({
      where: { id: scanId },
      select: { status: true, overallScore: true, updatedAt: true },
    });

    if (!scan || scan.status !== "completed") {
      return new NextResponse("Not Found", { status: 404 });
    }

    const score = scan.overallScore ?? 0;
    const svg = buildBadgeSvg(score);

    return new NextResponse(svg, {
      status: 200,
      headers: {
        "Content-Type": "image/svg+xml",
        "Cache-Control": "public, max-age=86400",
        Vary: "Accept-Encoding",
      },
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Badge error";
    return new NextResponse(message, { status: 500 });
  }
}

const LOGO_DATA_URI = "data:image/png;base64,";

function escapeSvg(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function buildBadgeSvg(score: number): string {
  const safeScore = Math.max(0, Math.min(100, Math.round(score)));
  const totalWidth = 300;
  const height = 40;
  const radius = 6;
  const borderWidth = 1;

  const leftWidth = 150;
  const rightWidth = totalWidth - leftWidth;

  // conduitscore-lockup-transparent.png is 480x274; scale to 30px tall
  const logoH = 30;
  const logoW = Math.round(logoH * (480 / 274));
  const logoX = (leftWidth - logoW) / 2;
  const logoY = (height - logoH) / 2;

  const scoreText = escapeSvg(`${safeScore}/100 AI-Visible`);
  const scoreX = leftWidth + rightWidth / 2;
  const scoreY = height / 2 + 1;

  const ariaLabel = escapeSvg(`ConduitScore Verified: ${safeScore}/100 AI-Visible`);

  return `<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="${totalWidth}" height="${height}" role="img" aria-label="${ariaLabel}">
  <title>${ariaLabel}</title>
  <defs>
    <linearGradient id="cs-bg-left" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#131320"/>
      <stop offset="100%" stop-color="#0a0a0f"/>
    </linearGradient>
    <linearGradient id="cs-bg-right" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#1a1030"/>
      <stop offset="100%" stop-color="#0d0a1a"/>
    </linearGradient>
    <clipPath id="cs-clip">
      <rect width="${totalWidth}" height="${height}" rx="${radius}" ry="${radius}"/>
    </clipPath>
  </defs>

  <!-- Outer border -->
  <rect
    x="${borderWidth / 2}"
    y="${borderWidth / 2}"
    width="${totalWidth - borderWidth}"
    height="${height - borderWidth}"
    rx="${radius}"
    ry="${radius}"
    fill="none"
    stroke="#6c3bff"
    stroke-width="${borderWidth}"
  />

  <!-- Background -->
  <g clip-path="url(#cs-clip)">
    <rect x="0" y="0" width="${leftWidth}" height="${height}" fill="url(#cs-bg-left)"/>
    <rect x="${leftWidth}" y="6" width="1" height="${height - 12}" fill="#6c3bff" opacity="0.5"/>
    <rect x="${leftWidth + 1}" y="0" width="${rightWidth - 1}" height="${height}" fill="url(#cs-bg-right)"/>
  </g>

  <!-- Logo image -->
  <image
    href="${LOGO_DATA_URI}"
    x="${logoX}"
    y="${logoY}"
    width="${logoW}"
    height="${logoH}"
    preserveAspectRatio="xMidYMid meet"
  />

  <!-- Score text -->
  <text
    x="${scoreX}"
    y="${scoreY}"
    font-family="-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif"
    font-size="13"
    font-weight="700"
    fill="#00d9ff"
    text-anchor="middle"
    dominant-baseline="middle"
    letter-spacing="0.2"
  >${scoreText}</text>
</svg>`;
}